const pregunta = ($node['Config1'].json.pregunta_usuario || '').trim();
const low = pregunta.toLowerCase();
const body = $node['Discord Webhook1'].json.body || {};
const channelId = String(body.channel_id || body.channelId || body.channel || '');
const pmChannels = new Set([
  $env.DISCORD_CHANNEL_TAREAS,
  $env.DISCORD_CHANNEL_AVANCES,
  $env.DISCORD_CHANNEL_BLOQUEOS,
  $env.DISCORD_CHANNEL_REPORTES,
  $env.DISCORD_CHANNEL_REUNIONES,
  $env.DISCORD_CHANNEL_ENTREGABLES,
  $env.DISCORD_CHANNEL_RIESGOS,
  $env.DISCORD_CHANNEL_ADMIN
].filter(Boolean).map(String));
const pmIntentHint = /^\/pm(\s|$)/i.test(pregunta)
  || (pmChannels.has(channelId) && /(tarea|avance|bloqueo|riesgo|reporte|reunion|reunión|decision|decisión|entregable|retrospectiva|pendiente|atraso|sprint|estado)/i.test(low));

// Objeto para almacenar los detalles del comando
const comando = {
  nombre: null,
  params: {},
  tipo: 'chat', // Default
  necesita_diff: false,
  error: null
};

// Si no es un comando, es un chat normal
if (!pregunta.startsWith('!')) {
  if (pmIntentHint) {
    comando.nombre = 'pm';
    comando.tipo = 'pm_project_manager';
  } else if (pregunta.includes('ha saltado al servidor') || pregunta.includes('joined the server')) {
    comando.error = 'Ignorado';
  } else {
    comando.necesita_diff = /(codig|commit|diff|revisa|calidad|pull request|\bpr\b|merge)/.test(low);
  }
} else {
  const partes = pregunta.split(' ');
  const cmd = partes[0].toLowerCase();

  switch (cmd) {
    case '!ayuda':
    case '!help':
      comando.nombre = 'ayuda';
      comando.tipo = 'ayuda';
      break;
    case '!kpis':
      comando.nombre = 'kpis';
      comando.tipo = 'kpis';
      break;
    case '!reporte':
      comando.nombre = 'reporte';
      comando.tipo = 'reporte';
      // Opcional: capturar número de días
      const dias = parseInt(partes[1], 10);
      if (!isNaN(dias) && dias > 0) {
        comando.params.dias = dias;
      } else {
        comando.params.dias = 7; // Default
      }
      break;
    case '!riesgos':
      comando.nombre = 'riesgos';
      comando.tipo = 'chat'; // Usará el flujo de chat pero con un contexto específico
      break;
    case '!hitos':
      comando.nombre = 'hitos';
      comando.tipo = 'chat'; // Igual que riesgos
      break;
    case '!revisar':
      comando.nombre = 'revisar';
      comando.tipo = 'chat';
      comando.necesita_diff = true;
      const repo = (partes[1] || '').toLowerCase();
      if (repo === 'backend' || repo === 'frontend') {
        comando.params.repo = repo;
      } else {
        comando.error = 'Debes especificar un repositorio: `!revisar backend` o `!revisar frontend`.';
      }
      break;
    case '!estado':
      comando.nombre = 'estado'; comando.tipo = 'chat'; comando.formato = 'estado'; break;
    case '!vencidas':
      comando.nombre = 'vencidas'; comando.tipo = 'chat'; comando.formato = 'vencidas'; break;
    case '!miembros':
      comando.nombre = 'miembros'; comando.tipo = 'chat'; comando.formato = 'miembros'; break;
    case '!commits':
      comando.nombre = 'commits'; comando.tipo = 'chat'; comando.formato = 'commits'; break;
    case '!ci':
      comando.nombre = 'ci'; comando.tipo = 'chat'; comando.formato = 'ci'; break;
    case '!progreso':
      comando.nombre = 'progreso'; comando.tipo = 'chat'; comando.formato = 'progreso'; break;
    case '!acciones':
      comando.nombre = 'acciones'; comando.tipo = 'pmo_query'; comando.formato = 'acciones'; break;
    case '!raid':
      comando.nombre = 'raid'; comando.tipo = 'pmo_query'; comando.formato = 'raid'; break;
    case '!logs':
      comando.nombre = 'logs'; comando.tipo = 'pmo_query'; comando.formato = 'logs'; break;
    case '!agenda':
    case '!calendario':
    case '!reuniones':
      comando.nombre = 'agenda'; comando.tipo = 'pmo_query'; comando.formato = 'agenda'; break;
    case '!reunion':
    case '!reunión':
      comando.nombre = 'reunion'; comando.tipo = 'pmo_meeting'; comando.formato = 'reunion';
      comando.params.titulo = partes.slice(1).join(' ').trim();
      break;
    case '!calidad':
      comando.nombre = 'calidad'; comando.tipo = 'chat'; comando.formato = 'calidad'; break;
    case '!stakeholder':
      comando.nombre = 'stakeholder'; comando.tipo = 'chat'; comando.formato = 'stakeholder'; break;
    case '!retro':
      comando.nombre = 'retro'; comando.tipo = 'chat'; comando.formato = 'retro'; break;
    case '!onboarding':
      comando.nombre = 'onboarding'; comando.tipo = 'chat'; comando.formato = 'onboarding';
      comando.params.usuario = partes.slice(1).join(' ').trim();
      break;
    case '!finops':
    case '!presupuesto':
    case '!budget':
      comando.nombre = 'finops'; comando.tipo = 'chat'; comando.formato = 'finops'; break;
    case '!capacidad':
    case '!forecast':
      comando.nombre = 'capacidad'; comando.tipo = 'chat'; comando.formato = 'capacidad'; break;
    case '!pto':
      comando.nombre = 'pto'; comando.tipo = 'chat'; comando.formato = 'pto';
      comando.params.miembro = partes[1] || '';
      comando.params.inicio = partes[2] || '';
      comando.params.fin = partes[3] || '';
      comando.params.motivo = partes.slice(4).join(' ').trim() || 'PTO';
      break;
    default:
      comando.error = `Comando \`${cmd}\` no reconocido. Usa \`!ayuda\` para ver la lista de comandos.`;
      break;
  }
}

// El objeto de salida ahora es más rico en información
return [{
  json: {
    pregunta,
    comando,
    tipo: comando.error ? 'error' : comando.tipo,
    necesita_diff: comando.necesita_diff,
    formato: comando.formato || 'chat',
    usuario: $node['Config1'].json.usuario_discord,
    channel_id: channelId,
    channel_name: body.channel_name || body.channelName || '',
    message_id: body.message_id || body.messageId || '',
    user_id: body.user_id || body.userId || '',
    content: pregunta
  }
}];

const row = $json || {};

// Si por alguna razon llega texto cacheado, devuelve directo
if (typeof row.value === 'string' && !row.fecha_ejecucion && !row.kpis_json) {
  return [{ json: { text: row.value } }];
}

let k = row.kpis_json || {};

if (typeof k === 'string') {
  try {
    k = JSON.parse(k);
  } catch (e) {
    k = {};
  }
}

const val = (v, fallback = 'N/A') => (v === undefined || v === null || v === '') ? fallback : v;
const fecha = row.fecha_ejecucion ? new Date(row.fecha_ejecucion) : null;
const fechaStr = fecha && !isNaN(fecha) ? fecha.toLocaleString('es-EC') : 'sin fecha';

const lines = [
  'KPIs PetSafe (' + fechaStr + ')',
  '',
  'Progreso sprint: ' + val(row.progreso_pct, 0) + '%',
  'Tareas vencidas: ' + val(row.tareas_vencidas, 0),
  'Velocidad: ' + val(k.velocidad_tareas_por_dia, 0) + ' tareas/dia (completadas 7d: ' + val(k.completadas_7d, 0) + ')',
  '% a tiempo: ' + val(k.pct_a_tiempo, 0) + '%',
  'Commits 14d: ' + val(k.commits_14d, 0) + ' (' + val(k.commits_por_dia, 0) + '/dia)',
  'PR avg open: ' + val(k.pr_open_time_dias, 0) + ' dias',
  'PR merge ratio 30d: ' + val(k.pr_merge_ratio_30d, 0) + '%',
  'Dias hasta fin: ' + val(k.dias_hasta_fin, 'N/A'),
  'Proyeccion: ' + val(k.proyeccion, 'N/A')
];

return [{ json: { text: lines.join('\n') } }];

const now = new Date();
const MS_PER_DAY = 86400000;
function daysBetween(from, to) {
  if (!from || !to) return null;
  const diff = new Date(to) - new Date(from);
  return Math.round(diff / 86400000);
}

function isValidDate(d) { return d instanceof Date && !Number.isNaN(d.getTime()); }
function parseDate(value) { if (!value) return null; const d = new Date(value); return isValidDate(d) ? d : null; }
function safeString(value, fallback = '') { return typeof value === 'string' ? value : fallback; }
function safeArray(value) { return Array.isArray(value) ? value : []; }
function truncate(value, max) { const str = safeString(value, ''); return str.length > max ? str.slice(0, max) : str; }
function getFirstJson(nodeName, fallback = null) { try { const item = $(nodeName).first(); return item && item.json ? item.json : fallback; } catch (e) { return fallback; } }
function getAllJson(nodeName) { try { const items = $(nodeName).all(); return Array.isArray(items) ? items.map(i => i?.json || {}) : []; } catch (e) { return []; } }
function coalesce(...values) { for (const v of values) { if (v !== undefined && v !== null && v !== '') return v; } return null; }
function simplifyCommit(c, type) { return { msg: truncate(c.commit?.message, 60), auth: truncate(c.commit?.author?.name, 20), date: c.commit?.author?.date, type: type }; }

const router = getFirstJson('Router Comandos1', {});
const config = getFirstJson('Config', {});
const pregunta = safeString(router.pregunta, '').trim();
const usuario = safeString(router.usuario, 'desconocido');
const needDiff = !!router.necesita_diff;
const geminiKey = safeString(config.GEMINI_API_KEY, '');

let ctx;
const cached = getFirstJson('Redis Get CTX', {});

if (cached && cached.ctx_data) {
  // CACHE HIT!
  ctx = typeof cached.ctx_data === 'string' ? JSON.parse(cached.ctx_data) : cached.ctx_data;
} else {
  // CACHE MISS: Build Context
  const cards = getAllJson('Trello Cards1');
  const lists = getAllJson('Trello Lists1');
  const members = getAllJson('Trello Members1');
  const bCommits = getAllJson('GH Back Commits1');
  const fCommits = getAllJson('GH Front Commits1');
  const bPRs = getAllJson('GH Back PRs1');
  const fPRs = getAllJson('GH Front PRs1');
  const historial = getAllJson('PG Historial1');
  const recos = getAllJson('PG Recomendaciones1');
  const hitos = getAllJson('PG Hitos1');

  const tareas = cards.map(c => {
    const l = lists.find(list => list.id === c.idList);
    const m = c.idMembers?.length ? members.find(mem => mem.id === c.idMembers[0]) : null;
    return { id: c.id, nombre: c.name, lista: l ? l.name : 'Desconocida', completada: !!c.dueComplete, miembro: m ? m.fullName : 'Sin asignar', vencimiento: parseDate(c.due) };
  });

  const tareasPendientes = tareas.filter(t => !t.completada);
  const vencidas = tareasPendientes.filter(t => t.vencimiento && t.vencimiento < now).length;
  const porVencer = tareasPendientes.filter(t => t.vencimiento && t.vencimiento >= now && (t.vencimiento - now) / MS_PER_DAY <= 3).length;

  const kpis = historial.length > 0 ? historial[0] : {};
  const recomendacionesPrevias = recos.slice(0, 3).map(r => ({ desc: r.descripcion, aplicada: r.aplicada }));
  const hitosActivos = hitos.filter(h => !h.completado).map(h => ({ n: h.nombre, fin: h.fecha_fin, d: daysBetween(now, parseDate(h.fecha_fin)) }));

  ctx = {
    fecha_actual: now.toISOString(),
    usuario,
    tareas: { total: tareas.length, vencidas, por_vencer_3dias: porVencer, completadas_count: tareas.filter(t => t.completada).length, recientes_completadas: tareas.filter(t => t.completada).slice(0, 15).map(t => t.nombre), resumen_todas: tareas.map(t => ({n: t.nombre, l: t.lista, c: t.completada ? 1 : 0})), distribucion: tareas.reduce((acc, t) => { acc[t.lista] = (acc[t.lista] || 0) + 1; return acc; }, {}) },
    github: { commits_back_recientes: bCommits.slice(0, 8).map(c => simplifyCommit(c, 'backend')), commits_front_recientes: fCommits.slice(0, 8).map(c => simplifyCommit(c, 'frontend')) },
    kpis_ultimo_analisis: kpis, hitos_proximos: hitosActivos.slice(0, 5), recomendaciones_previas: recomendacionesPrevias
  };
}

let diffBack = null; let diffFront = null;
if (needDiff) {
  const repo = router.comando?.params?.repo;
  if (!repo || repo === 'backend') diffBack = getFirstJson('Diff Backend1', null);
  if (!repo || repo === 'frontend') diffFront = getFirstJson('Diff Frontend1', null);
}
let diffInfo = null;
if (diffBack || diffFront) { diffInfo = { backend: diffBack ? truncate(JSON.stringify(diffBack), 3000) : null, frontend: diffFront ? truncate(JSON.stringify(diffFront), 3000) : null }; }
ctx.diff_commits = diffInfo;

const system_prompt = `Eres el Gestor de Proyecto IA para "PetSafe". Tu objetivo es dar respuestas precisas. REGLAS ESTRICTAS:
1. MAX 1800 caracteres. SIN MARKDOWN complejo.
2. Si preguntan por estado general: resume KPIs, tareas y fechas clave.
3. Si la pregunta es simple (ej "hay vencidas?"), responde directo.
4. Considera hitos proximos y dias hasta fin.
5. Si preguntan por riesgos, analiza las tareas vencidas, por vencer y la carga de trabajo en el contexto.
6. Si el comando es '!revisar backend' o '!revisar frontend', usa la herramienta Tool Ver CI Backend o Tool Ver CI Frontend para obtener el estado del CI, luego da un resumen tecnico del ultimo commit y si las pruebas pasaron.\n7. COMPLEMENTA CADA RESPUESTA con sugerencias útiles y accionables (ej. reasignar tareas, priorizar X, revisar cuellos de botella) basándote en el contexto, siempre que aplique.
CONTEXTO (${now.toISOString()}):
${JSON.stringify(ctx, null, 2)}
PREGUNTA DE ${usuario}:
${pregunta || 'Pregunta no disponible'}`;

const final_user_prompt = pregunta || 'Hola, por favor dame un resumen del estado del proyecto.';
return [{ json: { system_prompt, user_prompt: final_user_prompt, gemini_key: geminiKey, pregunta, usuario, ctx_data: ctx, from_cache: !!(cached && cached.ctx_data) } }];

const now = new Date();
const cards = $('Trello Cards1').all().map(i=>i.json);
const total = cards.length;
const done = cards.filter(c=>c.dueComplete).length;
const pct = total>0?Math.round(done/total*100):0;
const pend = cards.filter(c=>!c.dueComplete).length;

// Distribution by list
const lists = $('Trello Lists1').all().map(i=>i.json);
const listById = Object.fromEntries(lists.map(l=>[l.id,l.name]));
const dist = {};
for(const c of cards){
  const l = listById[c.idList]||'?';
  if(!dist[l]) dist[l]={total:0,done:0};
  dist[l].total++;
  if(c.dueComplete) dist[l].done++;
}

// Next milestone from hitos table
const hitos = $('PG Hitos1').all().map(i=>i.json);
const nextHito = hitos.filter(h=>!h.completado).sort((a,b)=>new Date(a.fecha_fin)-new Date(b.fecha_fin))[0];
const diasHito = nextHito ? Math.round((new Date(nextHito.fecha_fin)-now)/86400000) : '?';

const bar='█'.repeat(Math.round(pct/10))+'░'.repeat(10-Math.round(pct/10));
const emojiPct = pct>=80?'🟢':pct>=50?'🟡':'🔴';

const lines = [
  '**📊 ESTADO DEL PROYECTO PetSafe**',
  `\`[${bar}] ${pct}%\`  ${emojiPct}`,
  `✅ Completadas: **${done}/${total}** | ⏳ Pendientes: **${pend}**`,
  '',
  '**Por fase:**',
  ...Object.entries(dist).map(([l,s])=>`  ${s.done===s.total?'✅':'🔲'} ${l}: ${s.done}/${s.total}`),
  '',
  nextHito ? `⏰ Próximo hito: **${nextHito.nombre}** en **${diasHito}d** (${new Date(nextHito.fecha_fin).toLocaleDateString('es-EC')})` : ''
].filter(l=>l!==undefined);


lines.push('');
if (pend > 0) {
  if (pend > 5 && pct < 80) {
    lines.push('💡 **Sugerencia:** Hay bastantes tareas pendientes (' + pend + '). Asegúrate de revisar cuellos de botella y priorizar el próximo hito.');
  } else {
    lines.push('💡 **Sugerencia:** ¡Buen ritmo! Enfóquense en cerrar las ' + pend + ' tareas pendientes para avanzar de fase.');
  }
} else {
  lines.push('💡 **Sugerencia:** Excelente trabajo. Todo está al día. Considera iniciar la planificación del siguiente sprint.');
}
return [{json:{respuesta:lines.join('\n')}}];

const cards = $('Trello Cards1').all().map(i=>i.json);
const lists = $('Trello Lists1').all().map(i=>i.json);
const members = $('Trello Members1').all().map(i=>i.json);
const listById = Object.fromEntries(lists.map(l=>[l.id,l.name]));
const memById = Object.fromEntries(members.map(m=>[m.id,m.fullName||m.username]));
const now = new Date();
const venc = cards.filter(c=>c.due&&!c.dueComplete&&new Date(c.due)<now);
if(!venc.length) return [{json:{respuesta:'✅ No hay tareas vencidas.\n\n💡 **Sugerencia:** ¡Excelente! Mantén el monitoreo activo para prevenir posibles retrasos.'}}];
const lines = ['**🔴 TAREAS VENCIDAS**',''];
for(const c of venc.slice(0,10)){
  const dias = Math.floor((now-new Date(c.due))/86400000);
  const resp = (c.idMembers||[]).map(id=>memById[id]||id).join(', ') || 'sin asignar';
  lines.push(`• **${c.name}**`);
  lines.push(`  Lista: ${listById[c.idList]||'?'} | Resp: ${resp} | Hace ${dias}d`);
}
if(venc.length>10) lines.push(`...y ${venc.length-10} más`);

lines.push('');
lines.push('💡 **Sugerencia:** Contacta a los responsables (' + [...new Set(venc.flatMap(c => c.idMembers || []).map(id => memById[id]||'Sin asignar'))].join(', ') + ') para evaluar bloqueos o redistribuir fechas límite de inmediato.');
return [{json:{respuesta:lines.join('\n')}}];

const cards = $('Trello Cards1').all().map(i=>i.json);
const members = $('Trello Members1').all().map(i=>i.json);
const memById = Object.fromEntries(members.map(m=>[m.id,m.fullName||m.username]));
const now = new Date();
const stats = {};
for(const c of cards){
  const seen = new Set();
  for(const id of (c.idMembers||[])){
    if(seen.has(id)) continue; // deduplicate per card
    seen.add(id);
    const name = memById[id]||id;
    if(!stats[name]) stats[name]={asig:0,done:0,pend:0};
    stats[name].asig++;
    if(c.dueComplete) stats[name].done++;
    else stats[name].pend++;
  }
}
const rows = ['Miembro          Asig Done Pend',
              '─────────────────────────────────'];
for(const [name,s] of Object.entries(stats)){
  const short = name.split(' ').slice(0,2).join(' ').slice(0,16).padEnd(16);
  rows.push(`${short} ${String(s.asig).padStart(4)} ${String(s.done).padStart(4)} ${String(s.pend).padStart(4)}`);
}
return [{json:{respuesta:'**👥 CARGA DEL EQUIPO**\n```\n'+rows.join('\n')+'\n```'}}];

const bC = $('GH Back Commits1').all().map(i=>i.json).slice(0,5);
const fC = $('GH Front Commits1').all().map(i=>i.json).slice(0,5);
const ago = dateStr => {
  const d = Math.floor((new Date()-new Date(dateStr))/86400000);
  return d===0?'hoy':d===1?'ayer':`hace ${d}d`;
};
const fmt = (c,repo)=>{
  const sha = (c.sha||'').slice(0,7);
  const autor = (c.commit?.author?.name||'?').split(' ')[0];
  const fecha = ago(c.commit?.author?.date);
  const msg = (c.commit?.message||'').split('\n')[0].slice(0,60);
  return `\`${sha}\` **${autor}** (${fecha}): ${msg}`;
};
const lines = [
  '**📝 ÚLTIMOS COMMITS**',
  '**Backend:**',
  ...bC.map(c=>fmt(c,'back')),
  '',
  '**Frontend:**',
  ...fC.map(c=>fmt(c,'front'))
];

lines.push('');
if(bC.length === 0 && fC.length === 0) {
  lines.push('💡 **Sugerencia:** No hay actividad de código reciente. Revisa si el equipo está atascado o en fase de planificación.');
} else {
  lines.push('💡 **Sugerencia:** Revisa que cada commit reciente esté asociado a una tarea o issue para mantener la trazabilidad.');
}
return [{json:{respuesta:lines.join('\n')}}];

const bRuns = $('GH Back CI Runs').first()?.json?.workflow_runs || [];
const fRuns = $('GH Front CI Runs').first()?.json?.workflow_runs || [];
const bR = bRuns[0];
const fR = fRuns[0];
const emo = s => s==='success'?'✅':s==='failure'?'❌':s==='in_progress'?'🔄':s==='cancelled'?'⚫':'⚪';
const ago = dateStr => {
  if(!dateStr) return '';
  const d = Math.floor((new Date()-new Date(dateStr))/86400000);
  return d===0?' (hoy)':d===1?' (ayer)':` (hace ${d}d)`;
};
const fmt = (r, label) => {
  if(!r) return `⚪ **${label}**: sin datos de CI`;
  const status = r.conclusion || r.status;
  const wf = r.name || 'workflow';
  const branch = r.head_branch;
  const actor = r.actor?.login || '?';
  const date = ago(r.created_at);
  return `${emo(status)} **${label}** — ${status}${date}\n  📋 ${wf} | 🌿 ${branch} | 👤 ${actor}`;
};
const lines = [
  '**🔧 ESTADO CI/CD**',
  fmt(bR,'Backend'),
  fmt(fR,'Frontend'),
  '',
  '🌐 Back deploy: VPS (STRATIUM-UTA)',
  '🌐 Front deploy: https://pet-safe-six.vercel.app'
];
return [{json:{respuesta:lines.join('\n')}}];

const cards = $('Trello Cards1').all().map(i=>i.json);
const h = $('PG Historial1').first()?.json||{};
const kpis=(typeof h.kpis_json==='string'?JSON.parse(h.kpis_json):h.kpis_json)||{};
const now=new Date();
const total=cards.length, done=cards.filter(c=>c.dueComplete).length;
const pend=cards.filter(c=>!c.dueComplete&&!(c.due&&new Date(c.due)<now)).length;
const venc=cards.filter(c=>c.due&&!c.dueComplete&&new Date(c.due)<now).length;
const pct=total>0?Math.round(done/total*100):0;
const bar='█'.repeat(Math.round(pct/10))+'░'.repeat(10-Math.round(pct/10));
const lines=[
  '**🏁 PROGRESO DEL SPRINT**',
  `\`[${bar}] ${pct}%\``,
  `Completadas: **${done}** | Pendientes: **${pend}** | Vencidas: **${venc}**`,
  `Velocidad: **${kpis.velocidad_tareas_por_dia??'?'}** t/día | Commits/día: **${kpis.commits_por_dia??'?'}**`,
  `Proyección: **${kpis.proyeccion??'sin datos'}** | Días hasta fin: **${kpis.dias_hasta_fin??'?'}**`
];

lines.push('');
if (kpis.proyeccion_a_tiempo === false) {
  lines.push('💡 **Sugerencia:** La proyección actual indica un riesgo de retraso. Se requiere acción inmediata para acelerar el desarrollo o reducir el alcance.');
} else {
  lines.push('💡 **Sugerencia:** La proyección está en camino. Mantén la velocidad actual (' + (kpis.velocidad_tareas_por_dia || 0) + ' tareas/día) para asegurar la entrega.');
}
return [{json:{respuesta:lines.join('\n')}}];

