CREATE TABLE IF NOT EXISTS events_outbox (outbox_id BIGSERIAL PRIMARY KEY, event_id TEXT, target TEXT NOT NULL DEFAULT 'discord', action TEXT NOT NULL DEFAULT 'notify', idempotency_key TEXT, payload JSONB NOT NULL DEFAULT '{}'::jsonb, status TEXT NOT NULL DEFAULT 'pending', retry_count INTEGER NOT NULL DEFAULT 0, scheduled_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), sent_at TIMESTAMPTZ, last_error TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS events_inbox (event_id TEXT PRIMARY KEY, source TEXT, event_type TEXT, received_at TIMESTAMPTZ DEFAULT NOW(), correlation_id TEXT, actor TEXT, processing_status TEXT DEFAULT 'pending', retry_count INTEGER DEFAULT 0, last_error TEXT, payload JSONB DEFAULT '{}'::jsonb, normalized JSONB DEFAULT '{}'::jsonb);
SELECT
  COALESCE((SELECT json_agg(t) FROM (SELECT action_id, title, description, owner, priority, status, due_date, created_at FROM pmo_action_items WHERE status = 'open' ORDER BY due_date ASC NULLS LAST, created_at DESC LIMIT 12) t), '[]'::json) AS actions,
  COALESCE((SELECT json_agg(t) FROM (SELECT raid_id, item_type, title, description, severity, owner, status, mitigation, due_date, created_at FROM pmo_raid_items WHERE status = 'open' ORDER BY CASE severity WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END, due_date ASC NULLS LAST LIMIT 12) t), '[]'::json) AS raid,
  COALESCE((SELECT json_agg(t) FROM (SELECT snapshot_id, health_score, health_status, summary, created_at FROM pmo_health_snapshots ORDER BY created_at DESC LIMIT 3) t), '[]'::json) AS health,
  COALESCE((SELECT json_agg(t) FROM (SELECT run_id, workflow_name, status, started_at, correlation_id, error_details FROM workflow_runs_audit ORDER BY started_at DESC LIMIT 8) t), '[]'::json) AS audit,
  COALESCE((SELECT json_agg(t) FROM (SELECT outbox_id, status, retry_count, scheduled_at, last_error FROM events_outbox WHERE status IN ('dead','failed','pending','sending') ORDER BY scheduled_at DESC LIMIT 8) t), '[]'::json) AS outbox,
  COALESCE((SELECT json_agg(t) FROM (SELECT event_id, source, event_type, processing_status, retry_count, received_at, last_error FROM events_inbox WHERE processing_status IN ('error','failed','pending','processing','ingested') ORDER BY received_at DESC LIMIT 8) t), '[]'::json) AS inbox,
  COALESCE((SELECT json_agg(t) FROM (SELECT m.meeting_id, m.title, m.status, m.priority, m.scheduled_for, m.duration_minutes, m.scheduling_status, m.requested_by, COALESCE((SELECT json_agg(i) FROM (SELECT name, role, is_client FROM pmo_meeting_invitees WHERE meeting_id = m.meeting_id ORDER BY is_client DESC, name) i), '[]'::json) AS invitees FROM pmo_meetings m WHERE m.status IN ('scheduled','confirmed','needs_reschedule') AND COALESCE(m.scheduled_for, m.created_at) >= NOW() - INTERVAL '1 day' ORDER BY COALESCE(m.scheduled_for, m.created_at) ASC LIMIT 10) t), '[]'::json) AS meetings;

