const formato = $('Router Comandos1').first().json.formato;
const parse = (v) => Array.isArray(v) ? v : (typeof v === 'string' ? JSON.parse(v || '[]') : []);
const actions = parse($json.actions);
const raid = parse($json.raid);
const health = parse($json.health);
const audit = parse($json.audit);
const outbox = parse($json.outbox);
const inbox = parse($json.inbox);
const meetings = parse($json.meetings);
const fmt = (d) => d ? new Date(d).toLocaleDateString('es-EC', { timeZone: 'America/Guayaquil', month: 'short', day: 'numeric' }) : 'sin fecha';
const short = (s, n = 110) => String(s || '').length > n ? String(s || '').slice(0, n - 1) + '…' : String(s || '');
let respuesta = '';
if (formato === 'acciones') {
  respuesta = actions.length
    ? ['**Acciones PMO abiertas**', ...actions.map((a, i) => `${i + 1}. [${a.priority || 'medium'}] ${a.title} — owner: ${a.owner || 'sin owner'} — due: ${fmt(a.due_date)}`)].join('\n')
    : 'No hay acciones PMO abiertas. Buen momento para respirar y mirar el tablero.';
} else if (formato === 'raid') {
  respuesta = raid.length
    ? ['**RAID abierto**', ...raid.map((r, i) => `${i + 1}. [${r.severity || 'medium'}] ${r.item_type}: ${r.title} — owner: ${r.owner || 'sin owner'} — mitigación: ${short(r.mitigation || r.description, 90)}`)].join('\n')
    : 'No hay RAID abierto registrado.';

} else if (formato === 'agenda') {
  const fmtFull = (d) => d ? new Date(d).toLocaleString('es-EC', { timeZone: 'America/Guayaquil', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' }) : 'sin horario';
  const parseInvitees = (v) => Array.isArray(v) ? v : (typeof v === 'string' ? JSON.parse(v || '[]') : []);
  respuesta = meetings.length
    ? ['**Agenda PMO próxima**', ...meetings.map((m, i) => {
        const inv = parseInvitees(m.invitees).map(x => x.name).join(', ') || 'sin invitados';
        return `${i + 1}. [${m.status}] ${m.title} — ${fmtFull(m.scheduled_for)} — ${m.duration_minutes || 30} min — ${inv}`;
      }), '', 'Panel completo: `/webhook/pm-calendar?token=TU_SECRETO`'].join('\n')
    : 'No hay reuniones PMO próximas. Puedes crear una con `!reunion tema mañana 10am`.';
} else if (formato === 'logs') {
  const h = health[0];
  const lines = ['**PM Logs / Salud del bot**'];
  if (h) lines.push(`Health PMO: ${String(h.health_status || '').toUpperCase()} (${h.health_score}/100) — ${short(h.summary, 100)}`);
  lines.push(`Audit recientes: ${audit.length}`);
  lines.push(`Outbox pendientes/problema: ${outbox.length}`);
  lines.push(`Inbox pendientes/problema: ${inbox.length}`);
  const failures = audit.filter(a => a.status === 'error').slice(0, 3);
  if (failures.length) {
    lines.push('', '**Errores recientes:**');
    failures.forEach((f, i) => lines.push(`${i + 1}. ${f.workflow_name || 'workflow'} — ${fmt(f.started_at)} — ${short(JSON.stringify(f.error_details || {}), 90)}`));
  }
  lines.push('', 'Panel completo: `/webhook/pm-logs?token=TU_SECRETO`');
  respuesta = lines.join('\n');
} else {
  respuesta = 'Formato PMO no reconocido.';
}
return [{ json: { respuesta } }];

const router = $('Router Comandos1').first().json;
const pregunta = router.pregunta || '';
const rawTitle = router.comando?.params?.titulo || pregunta.replace(/^!reuni[oó]n\s*/i, '').trim();
const title = rawTitle || 'Reunión PM solicitada desde Discord';
return [{ json: {
  title,
  objective: 'Coordinar seguimiento PM solicitado desde Discord.',
  context: pregunta,
  source: 'discord_command',
